using System;
using System.IO;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;
using System.Data.SqlClient;
using System.Linq;
using System.Collections.Generic;
using System.Text;

namespace SecureAzureFunction
{
    public static class SecureHttpTrigger
    {
        [FunctionName("SecureHttpTrigger")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
            ILogger log)
        {
            var correlationId = Guid.NewGuid().ToString();
            
            try
            {
                log.LogInformation($"[{correlationId}] Function triggered");

                // Log sanitized request information
                LogSanitizedRequestInfo(req, log, correlationId);

                string requestBody = await new StreamReader(req.Body).ReadToEnd();
                
                // Log sanitized body (remove sensitive data)
                var sanitizedBody = SanitizeRequestBody(requestBody);
                log.LogInformation($"[{correlationId}] Request body (sanitized): {sanitizedBody}");

                dynamic data = JsonConvert.DeserializeObject(requestBody);
                string userId = data?.userId;

                if (string.IsNullOrEmpty(userId))
                {
                    log.LogWarning($"[{correlationId}] Missing userId parameter");
                    return new BadRequestObjectResult("Please pass a userId");
                }

                // Log user context without sensitive data
                log.LogInformation($"[{correlationId}] Processing request for user: {MaskUserId(userId)}");

                // Execute database query with sanitized logging
                var result = await ExecuteDatabaseQuery(userId, log, correlationId);

                log.LogInformation($"[{correlationId}] Request completed successfully");
                
                return new OkObjectResult(result);
            }
            catch (Exception ex)
            {
                // Log exception with sanitized details
                LogSanitizedException(ex, log, correlationId);
                return new StatusCodeResult(StatusCodes.Status500InternalServerError);
            }
        }

        private static void LogSanitizedRequestInfo(HttpRequest req, ILogger log, string correlationId)
        {
            // Log only non-sensitive headers
            var safeHeaders = new List<string> { "Content-Type", "Accept", "User-Agent", "Content-Length" };
            var headerInfo = new StringBuilder();
            
            foreach (var header in req.Headers.Where(h => safeHeaders.Contains(h.Key, StringComparer.OrdinalIgnoreCase)))
            {
                headerInfo.AppendLine($"{header.Key}: {header.Value}");
            }

            log.LogInformation($"[{correlationId}] Request headers (safe only):\n{headerInfo}");
            log.LogInformation($"[{correlationId}] Method: {req.Method}, Path: {req.Path}");
            
            // Log that authentication was present without logging the token
            if (req.Headers.ContainsKey("Authorization"))
            {
                log.LogInformation($"[{correlationId}] Authorization header present");
            }
        }

        private static string SanitizeRequestBody(string body)
        {
            if (string.IsNullOrEmpty(body))
                return "[empty]";

            try
            {
                var data = JsonConvert.DeserializeObject<Dictionary<string, object>>(body);
                var sensitiveFields = new[] { "password", "token", "secret", "apiKey", "authorization", "ssn", "creditCard", "email" };
                
                foreach (var field in sensitiveFields)
                {
                    if (data.ContainsKey(field))
                    {
                        data[field] = "[REDACTED]";
                    }
                }
                
                return JsonConvert.SerializeObject(data);
            }
            catch
            {
                return "[unable to parse - redacted for security]";
            }
        }

        private static string MaskUserId(string userId)
        {
            if (string.IsNullOrEmpty(userId) || userId.Length <= 4)
                return "***";
            
            return userId.Substring(0, 2) + "***" + userId.Substring(userId.Length - 2);
        }

        private static async Task<object> ExecuteDatabaseQuery(string userId, ILogger log, string correlationId)
        {
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
            
            // Log query structure without sensitive parameters
            log.LogInformation($"[{correlationId}] Executing database query for masked user: {MaskUserId(userId)}");

            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();
                
                // Use parameterized queries
                var query = "SELECT Id, Name, Email FROM Users WHERE UserId = @UserId";
                
                // Log query structure only, not parameter values
                log.LogInformation($"[{correlationId}] Query: SELECT Id, Name, Email FROM Users WHERE UserId = @UserId");
                
                using (var command = new SqlCommand(query, connection))
                {
                    command.Parameters.AddWithValue("@UserId", userId);
                    
                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        var results = new List<object>();
                        while (await reader.ReadAsync())
                        {
                            results.Add(new
                            {
                                Id = reader["Id"],
                                Name = reader["Name"],
                                Email = MaskEmail(reader["Email"].ToString())
                            });
                        }
                        
                        log.LogInformation($"[{correlationId}] Query returned {results.Count} results");
                        return results;
                    }
                }
            }
        }

        private static string MaskEmail(string email)
        {
            if (string.IsNullOrEmpty(email) || !email.Contains("@"))
                return "***@***.***";
            
            var parts = email.Split('@');
            var localPart = parts[0].Length > 2 ? parts[0].Substring(0, 2) + "***" : "***";
            return $"{localPart}@{parts[1]}";
        }

        private static void LogSanitizedException(Exception ex, ILogger log, string correlationId)
        {
            // Log exception type and sanitized message
            log.LogError($"[{correlationId}] Exception Type: {ex.GetType().Name}");
            
            // Sanitize exception message to remove potential sensitive data
            var sanitizedMessage = SanitizeExceptionMessage(ex.Message);
            log.LogError($"[{correlationId}] Exception Message (sanitized): {sanitizedMessage}");
            
            // Log stack trace to Application Insights only (not to console/file logs)
            log.LogError(ex, $"[{correlationId}] Exception occurred");
            
            // Log inner exceptions
            if (ex.InnerException != null)
            {
                var sanitizedInnerMessage = SanitizeExceptionMessage(ex.InnerException.Message);
                log.LogError($"[{correlationId}] Inner Exception: {sanitizedInnerMessage}");
            }
        }

        private static string SanitizeExceptionMessage(string message)
        {
            if (string.IsNullOrEmpty(message))
                return "[no message]";
            
            // Remove potential connection strings, tokens, or sensitive data patterns
            var patterns = new[]
            {
                @"password=[^;]*",
                @"pwd=[^;]*",
                @"token=[^;]*",
                @"key=[^;]*",
                @"secret=[^;]*",
                @"bearer\s+[^\s]*",
                @"\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b"
            };
            
            var sanitized = message;
            foreach (var pattern in patterns)
            {
                sanitized = System.Text.RegularExpressions.Regex.Replace(
                    sanitized, 
                    pattern, 
                    "[REDACTED]", 
                    System.Text.RegularExpressions.RegexOptions.IgnoreCase
                );
            }
            
            return sanitized;
        }
    }
